Here is a simple C++ program that finds the *n*th Fibonacci number using recursion:

```cpp
#include <iostream>
using namespace std;

// Recursive function to compute the nth Fibonacci number
int fib(int n) {
    if (n <= 1)
        return n;           // Base cases: fib(0) = 0, fib(1) = 1
    return fib(n - 1) + fib(n - 2);  // Recursive relation
}

int main() {
    int n;
    cout << "Enter n: ";
    cin >> n;

    if (n < 0) {
        cout << "Please enter a non-negative integer." << endl;
        return 1;
    }

    cout << "Fibonacci number F(" << n << ") = " << fib(n) << endl;
    return 0;
}
```

