#include <iostream>
using namespace std;

// Recursive function to compute the nth term of the sequence
int seq(int n) {
    if (n == 0)
        return 0;       // a0 = 0
    if (n == 1)
        return -1;      // a1 = -1
    if (n == 2)
        return -1;      // a2 = -1

    // Recursive relation: a_n = a_{n-1} + a_{n-2} + a_{n-3}
    return seq(n - 1) + seq(n - 2) + seq(n - 3);
}

int main() {
    int n;
    cout << "Enter n: ";
    cin >> n;

    if (n < 0) {
        cout << "Please enter a non-negative integer." << endl;
        return 1;
    }

    cout << "Term a(" << n << ") = " << seq(n) << endl;
    return 0;
}
```

